// Parse GPT's analysis + merge into an enhanced brief.
const wh = $('Webhook').first().json.body;
const orig = wh.original_brief || {};

let raw;
try { raw = $input.first().json.output[0].content[0].text; }
catch(e) { throw new Error('No AI response text — unexpected OpenAI output structure.'); }
const cleaned = (raw || '').replace(/```json/gi, '').replace(/```/g, '').trim();

let analysis;
try { analysis = JSON.parse(cleaned); }
catch(e) { throw new Error('AI did not return valid JSON. Raw start: ' + cleaned.slice(0,200)); }

const enhanced_brief = {
  hook: analysis.adjusted_hook || orig.hook,
  key_message: analysis.adjusted_key_message || orig.key_message,
  emotional_angle: analysis.adjusted_emotional_angle || orig.emotional_angle,
  visual_direction: analysis.adjusted_visual_direction || orig.visual_direction,
  cta: analysis.adjusted_cta || orig.cta
};

return [{ json: {
  slot_id: wh.slot_id,
  business_id: wh.business_id,
  platform: wh.platform,
  feedback: wh.feedback,
  tone_shift: analysis.tone_shift || 'general adjustment',
  analysis_summary: analysis.summary || '',
  original_brief: orig,
  enhanced_brief: enhanced_brief,
  // exact payload WF-CAPTION expects (with the enhanced brief baked in)
  captionPayload: {
    slot_id: wh.slot_id,
    business_id: wh.business_id,
    platform: wh.platform,
    brief: enhanced_brief
  }
}}];

// Build the new variant record (version+1).
const an = $('Parse Analysis').first().json;
const cap = $input.first().json;

return [{ json: {
  variant_id: 'var_' + an.slot_id + '_v2_' + Date.now(),
  version: 2,
  slot_id: an.slot_id,
  business_id: an.business_id,
  platform: an.platform,
  caption: cap.caption,
  hashtags: cap.hashtags,
  char_count: cap.char_count,
  brief_used: an.enhanced_brief,
  feedback_addressed: an.feedback,
  tone_shift: an.tone_shift,
  analysis_summary: an.analysis_summary,
  regenerated_at: new Date().toISOString()
}}];
